## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$f = RandomVariableName(type=>'function');
$a = non_zero_random(2,9,1)*random(-1,1,2);
Context("Fraction");
$h = Fraction(non_zero_random(-9,9,1),non_zero_random(-9,9,1));
$k = Fraction(non_zero_random(-9,9,1),non_zero_random(-9,9,1));
Context()->noreduce('(-x)+y','(-x)-y');
$formula = Formula("$a(x - $h)^2 + $k");
Context("Interval");
$domain = Compute("(-inf,inf)");
$range = ($a > 0) ? Compute("[$k,inf)") : Compute("(-inf,$k]");
Context("Point");
$vertex = Compute("($h,$k)");
$posneg = ($a > 0) ? "positive" : "negative";
$updown = ($a > 0) ? "upward" : "downward";
$greatless = ($a > 0) ? "greater" : "less";

############################################################
# Body
############################################################

BEGIN_PGML
Let [`[$f]`] be defined by [`[$f](x)=[$formula]\text{.}`]
a.  What is the domain of [`[$f]\text{?}`]

    [_]{$domain}{10}

a.  What is the range of [`[$f]\text{?}`]

    [_]{$range}{10}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
a.  The function is quadratic, so the domain is [`[$domain]\text{.}`] There are no invalid inputs for this function.

a.  Since the formula is in vertex form, we can see that the graph of [`[$f]`] has a vertex at [`[$vertex]\text{.}`] Since the leading coefficient is [`[$a]`] which is [$posneg], the parabola opens [$updown]. So the range is all numbers [$greatless] than or equal to [`[$k]\text{.}`] So the range is [`[$range]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
